#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
using namespace std;
inline long long read()
{
	long long res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int Mod=2333,M=2410;
int inc[M][M],res[M][M],fac[M],ifac[M];
inline int qpow(int a,int b=Mod-2){int res=1;while(b){if(b&1)res=res*a%Mod;a=a*a%Mod;b=b>>1;}return res;}
inline void Init()
{
	inc[0][0]=1;rep(1,Mod,i){inc[i][0]=1;rep(1,i,j)inc[i][j]=(inc[i-1][j-1]+inc[i-1][j])%Mod;}
	res[0][0]=1;rep(0,Mod,i){res[i][0]=1;rep(1,Mod,j)res[i][j]=(inc[i][j]+res[i][j-1])%Mod;}
}
inline int C(int a,int b){return a<b?0:inc[a][b];}
inline int qC(long long a,long long b){return b?C(a%Mod,b%Mod)*qC(a/Mod,b/Mod)%Mod:1;}
inline int Cnt(long long a,long long b)
{
	if(!a||!b)return 1;if(a<=Mod&&b<=Mod)return res[a][b];
	return (Cnt(a/Mod,b/Mod-1)*res[a%Mod][Mod-1]+qC(a/Mod,b/Mod)*res[a%Mod][b%Mod])%Mod;
}
inline void Solve(){long long n=read(),k=read();printf("%d\n",Cnt(n,k));}
int main(){Init();int T=read();while(T--)Solve();}
